mapper.select:
SELECT a.id, a.cover_image as coverImage, a.title, a.author_name as authorName, c.name as categoryName, a.word_count as wordCount, a.chapter_count as chapterCount, a.summary, a.status, a.is_finished as isFinished, case a.is_finished when 0 then '封禁' when 1 then '完结' when 2 then '连载' when 3 then '停更' else '未知' end as isFinishedDesc, a.update_time as updateTime FROM articles a INNER JOIN categories c ON c.id = a.category_id
a.is_deleted = 0
AND a.title LIKE CONCAT('%', #{title}, '%')
AND a.author_name = #{authorName}
AND a.category_id = #{categoryId}
AND a.is_finished = #{isFinished}
AND a.status = #{status}
order by a.update_time desc

